import React, { useEffect, useRef, useState } from 'react'
import { FiChevronLeft, FiChevronRight } from 'react-icons/fi'
import { Link } from 'react-router-dom'

const NewArrivals = () => {
    const scrollref = useRef(null)
    const [isDragging, setDragging] = useState(false)
    const [startX, setStartX] = useState(0)
    const [scrollLeft, setScrollLeft] = useState(false)
    const [canScrollLeft, setCanScrollLeft] = useState(false)
    const [canScrollRight, setCanScrollRight] = useState(true)

    const newArrivals = [
        {
            id: 1,
            name: "Silver ring",
            price: 100000,
            image: "https://images.unsplash.com/photo-1605100804763-247f67b3557e"
        },
        {
            id: 2,
            name: "Silver Bangles",
            price: 20000,
            image: "data:image/jpeg;base64,"
        },
        {
            id: 3,
            name: "Manglesutra",
            price: 30000,
            image: "data:image/jpeg;base64,"
        },
        {
            id: 4,
            name: "Gold Ring",
            price: 4000,
            image: "data:image/jpeg;base64,"
        },
        {
            id: 5,
            name: "Gold Necklace",
            price: 3000,
            image: "data:image/jpeg;base64,"
        },
        {
            id: 6,
            name: "Gold Choker",
            price: 4000,
            image: "data:image/jpeg;base64,"
        },
        {
            id: 7,
            name: "Gold braclet",
            price: 3000,
            image: "data:image/jpeg;base64,"
        },
        {
            id: 8,
            name: "Silver Anklet",
            price: 4000,
            image: "data:image/jpeg;base64,"
        },
    ]

    const handleMouseDown = (e) => {
        setDragging(true)
        setStartX(e.pageX - scrollref.current.offsetLeft)
        setScrollLeft(scrollref.current.scrollLeft)
    }


    const handleMouseMove = (e) => {
        if (!isDragging) {
            return;
        }
        const x = e.pageX - scrollref.current.offsetLeft;
        const walk = x - startX;
        scrollref.current.scrollLeft = scrollLeft - walk;
    }

    const handleMouseUpOrLeave = (e) => {
        setDragging(false)

    }

    const scroll = (direction) => {
        const scrollAmount = direction === "left" ? -300 : 300;
        scrollref.current.scrollBy({ left: scrollAmount, behavior: 'smooth' })
    }
    // update scroll button 
    const updateScrollbutton = () => {
        const container = scrollref.current
        if (container) {
            const leftScroll = container.scrollLeft
            const rightScrollable = container.scrollWidth > leftScroll + container.clientWidth
            setCanScrollLeft(leftScroll > 0);
            setCanScrollRight(rightScrollable)
        }
        console.log({
            scrollLeft: container.scrollLeft,
            clientWidth: container.clientWidth,
            containerScrollWidth: container.scrollWidth,
            offsetLeft: scrollref.current.offsetLeft
        })
    }

    useEffect(() => {
        const container = scrollref.current;
        if (container) {
            container.addEventListener('scroll', updateScrollbutton)
            updateScrollbutton()
            return () => container.removeEventListener('scroll', updateScrollbutton)
        }
    }, [])
    return (
        <section className='py-16 px-4 lg:px-0'>
            <div className='container mx-auto text-center mb-10 relative'>
                <h2 className='text-3xl font-bold mb-4'>Explore New Arrivals</h2>
                <p className='text-lg text-[#C9A227]  mb-8'>
                    Discover our latest collection of stunning jewellery, crafted with precision and care.
                </p>

                {/* scroll button */}
                <div className='absolute right-0 bottom-[-30px] flex space-x-2'>
                    <button onClick={() => scroll("left")}
                        disabled={!canScrollLeft}
                        className={`p-2 rounded border ${canScrollLeft ? 'bg-white text-black' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}>
                        <FiChevronLeft className="text-2xl" />
                    </button>
                    <button onClick={() => scroll("right")}
                        disabled={!canScrollRight}
                        className={`p-2 rounded border ${canScrollRight ? 'bg-white text-black' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}>
                        <FiChevronRight className="text-2xl" />
                    </button>
                </div>
            </div>
            {/* scrollable content */}
            <div ref={scrollref}
                className={`container mx-auto overflow-x-scroll flex space-x-6 relative  ${isDragging ? "cursor-grabbing" : "cursor-grab"}`}
                onMouseDown={handleMouseDown}
                onMouseUp={handleMouseUpOrLeave}
                onMouseLeave={handleMouseUpOrLeave}
                onMouseMove={handleMouseMove}>
                {newArrivals.map((product) => (
                    <div key={product.id} className='min-w-[100%] sm:min-w-[50%] lg:min-w-[30%] relative'>
                        <img
                            src={product.image}
                            alt={product.name}
                            className='w-full h-[500px] object-cover rounded-lg'
                            draggable="false"
                        />
                        <div className='absolute bottom-0 left-0 right-0 bg-black/50 backdrop-blur-md text-white p-4 rounded-b-lg'>
                            <Link to={`/product/${product.id}`} className='block'>
                                <h4 className='font-medium'>{product.name}</h4>
                                <p className='mt-1'>₹{product.price}</p>
                            </Link>
                        </div>
                    </div>
                ))}
            </div>
        </section>
    )
}

export default NewArrivals
